module top_module( clock, reset, overflow_count );input clock;
	input reset;
	output [2:0] overflow_count; 
	reg [2:0] overflow_count; 

	always @(posedge clock or  posedge reset) 
	begin 
		if  (reset) 
			overflow_count = 0;   
		else if  ( overflow_count < 3'b111 )  
			overflow_count = overflow_count + 1;   
		else 
			overflow_count = 0;   
	end 
endmodule
